#!/usr/bin/env bash

# Generated by scripts/build-installer.sh — do not edit directly.

# Run on a fresh NixOS live ISO to bootstrap the system.

set -euo pipefail

DEST=””
USERNAME=””
INIT_PASS=””
KB_LAYOUT=“us”
BROWSER_CHOICE=””
ERRORS=()

# ── Colors & TUI ─────────────────────────────────────────────────────────────

R=’\033[0m’
BOLD=’\033[1m’
DIM=’\033[2m’
CY=’\033[36m’
GR=’\033[32m’
YE=’\033[33m’
RE=’\033[31m’
BL=’\033[34m’

hide_cursor()  { printf ‘\033[?25l’; }
show_cursor()  { printf ‘\033[?25h’; }
cursor_up()    { printf ‘\033[%dA’ “$1”; }
clear_line()   { printf ‘\033[2K\r’; }

trap ‘show_cursor’ EXIT

log() { echo -e “  ${DIM}▸${R} $*”; }
ok()  { echo -e “  ${GR}${BOLD}✓${R} $*”; }
warn(){ echo -e “  ${YE}${BOLD}⚠${R} $*”; ERRORS+=(”$*”); }
err() { echo -e “  ${RE}${BOLD}✗${R} $*”; ERRORS+=(“CRITICAL: $*”); }

phase_header() {
local num=”$1” title=”$2”
clear
echo -e “”
echo -e “  ${CY}${BOLD}╔══════════════════════════════════════════════╗${R}”
printf   “  ${CY}${BOLD}║${R}  ${BOLD}NixOS Installer${R}  ${DIM}│${R}  Phase %-2s of 11        ${CY}${BOLD}║${R}\n” “$num”
echo -e “  ${CY}${BOLD}╠══════════════════════════════════════════════╣${R}”
printf   “  ${CY}${BOLD}║${R}  ${BOLD}%-44s${R}${CY}${BOLD}║${R}\n” “$title”
echo -e “  ${CY}${BOLD}╚══════════════════════════════════════════════╝${R}”
echo -e “”
}

# ── TUI: arrow-key single-select ─────────────────────────────────────────────

tui_select() {
  local -n _result="$1"; shift
  local prompt="$1"; shift
  local items=("$@")
  local cur=0 total=${#items[@]} key esc

  hide_cursor
  echo -e "  ${BOLD}${prompt}${R}"
  echo ""

  _render_list() {
    for i in "${!items[@]}"; do
      if [ "$i" -eq "$cur" ]; then
        echo -e "  ${CY}${BOLD}▶  ${items[$i]}${R}"
      else
        echo -e "     ${DIM}${items[$i]}${R}"
      fi
    done
  }

  _redraw() {
    _render_list
  }

  _redraw

  while true; do
    IFS= read -r -s -n1 key
    if [ "$key" = $'\x1b' ]; then
      IFS= read -r -s -n1 esc
      IFS= read -r -s -n1 esc
      case "$esc" in
        A) [ "$cur" -gt 0 ] && (( cur-- )) || true ;;
        B) [ "$cur" -lt $(( total - 1 )) ] && (( cur++ )) || true ;;
      esac
    elif [ -z "$key" ] || [ "$key" = $'\r' ]; then
      break
    fi

    for _ in $(seq 1 $(( total + 2 ))); do
      clear_line
      cursor_up 1
    done
    clear_line
    echo -e "  ${BOLD}${prompt}${R}"
    echo ""
    _redraw
  done

  for _ in $(seq 1 $(( total + 2 ))); do
    clear_line
    cursor_up 1
  done
  clear_line
  show_cursor
  echo -e "  ${GR}${BOLD}✓${R} ${BOLD}${prompt}${R}  ${CY}${items[$cur]}${R}"
  echo ""
  _result="${items[$cur]}"
}

# ── TUI: checkbox multi-select ────────────────────────────────────────────────

tui_checkbox() {
  local -n _checked="$1"; shift
  local prompt="$1"; shift
  local items=("$@")
  local cur=0 total=${#items[@]} key esc
  local selected=()
  for _ in "${items[@]}"; do selected+=(0); done

  hide_cursor
  echo -e "  ${BOLD}${prompt}${R}"
  echo -e "  ${DIM}(↑↓ navigate · space = toggle · enter = continue)${R}"
  echo ""

  _render_cb() {
    for i in "${!items[@]}"; do
      local box="[ ]" col="$DIM"
      [ "${selected[$i]}" -eq 1 ] && box="[${GR}x${R}]" && col=""
      if [ "$i" -eq "$cur" ]; then
        echo -e "  ${CY}${BOLD}▶${R}  ${box} ${col}${items[$i]}${R}"
      else
        echo -e "     ${box} ${col}${DIM}${items[$i]}${R}"
      fi
    done
  }

  local render_lines=$(( total + 2 ))
  _render_cb

  while true; do
    IFS= read -r -s -n1 key
    if [ "$key" = $'\x1b' ]; then
      IFS= read -r -s -n1 esc
      IFS= read -r -s -n1 esc
      case "$esc" in
        A) [ "$cur" -gt 0 ] && (( cur-- )) || true ;;
        B) [ "$cur" -lt $(( total - 1 )) ] && (( cur++ )) || true ;;
      esac
    elif [ "$key" = " " ] && [ "$cur" -lt "$total" ]; then
      selected[$cur]=$(( 1 - selected[$cur] ))
    elif [ -z "$key" ] || [ "$key" = $'\r' ]; then
      break
    fi

    for _ in $(seq 1 "$render_lines"); do
      clear_line
      cursor_up 1
    done
    clear_line
    echo -e "  ${BOLD}${prompt}${R}"
    echo -e "  ${DIM}(↑↓ navigate · space = toggle · enter = continue)${R}"
    echo ""
    _render_cb
  done

  for _ in $(seq 1 "$render_lines"); do
    clear_line
    cursor_up 1
  done
  clear_line
  show_cursor

  _checked=()
  for i in "${!items[@]}"; do
    [ "${selected[$i]}" -eq 1 ] && _checked+=("${items[$i]}")
  done

  if [ ${#_checked[@]} -gt 0 ]; then
    echo -e "  ${GR}${BOLD}✓${R} ${BOLD}${prompt}${R}"
    for item in "${_checked[@]}"; do echo -e "    ${CY}▸${R} ${item}"; done
  else
    echo -e "  ${GR}${BOLD}✓${R} ${BOLD}${prompt}${R}  ${DIM}(none — English only)${R}"
  fi
  echo ""
}

# ── TUI: text input ───────────────────────────────────────────────────────────

tui_input() {
local -n _inp=”$1”; shift
local prompt=”$1” default=”${2:-}”
local hint=””
[ -n “$default” ] && hint=” ${DIM}[${default}]${R}”
printf “  ${BOLD}%s${R}%b  “ “$prompt” “$hint”
IFS= read -r _inp
[ -z “$_inp” ] && _inp=”$default”
echo “”
}

# ── TUI: masked password input ────────────────────────────────────────────────

tui_password() {
local -n _pw=”$1”; shift
local prompt=”$1” default=”${2:-}”
local _char _typed=””
printf “  ${BOLD}%s${R} ${DIM}(hidden · enter = use default: %s)${R}  “ “$prompt” “$default”
while IFS= read -r -s -n1 _char; do
if [ -z “$_char” ]; then
break
elif [ “$_char” = $’\x7f’ ] || [ “$_char” = $’\b’ ]; then
if [ -n “$_typed” ]; then
_typed=”${_typed%?}”
printf ‘\b \b’
fi
else
_typed+=”$_char”
printf ‘*’
fi
done
echo “”
echo “”
[ -z “$_typed” ] && _pw=”$default” || _pw=”$_typed”
}

# ── TUI: yes/no ───────────────────────────────────────────────────────────────

tui_yesno() {
local -n _yn=”$1”; shift
local choice
tui_select choice “$1” “Yes” “No”
[ “$choice” = “Yes” ] && _yn=1 || _yn=0
}

