_KB_OPTS=(
“Russian          (ru)”
“Spanish          (es)”
“German           (de)”
“French           (fr)”
“Ukrainian        (ua)”
“Italian          (it)”
“Portuguese       (pt)”
“Polish           (pl)”
“Turkish          (tr)”
