# ═════════════════════════════════════════════════════════════════════════════

# Phase 8: Disk Formatting

# ═════════════════════════════════════════════════════════════════════════════

phase_header “8” “Disk Formatting”

if [ “$AUTO_INSTALL” -eq 0 ]; then
echo -e “  ${DIM}Manual mode — skipping disk formatting.${R}”
echo “”
echo -e “  Format ${CY}${PRIMARY_DEV}${R} yourself, then:”
echo -e “    ${BOLD}sudo nixos-generate-config –root /mnt${R}”
echo -e “    ${BOLD}sudo nixos-install –flake /etc/nixos#nixos${R}”
read -r -s -p “  Press Enter to continue…” _
echo “”
else
echo -e “  ${YE}${BOLD}WARNING:${R} All data on ${CY}${BOLD}${PRIMARY_DEV}${R} will be destroyed.”
echo “”
read -r -s -p “  Press Enter to confirm and begin formatting…” _
echo “”

log “Partitioning ${PRIMARY_DEV}…”
if sudo parted -s “$PRIMARY_DEV” –   
mklabel gpt   
mkpart ESP fat32 1MiB 512MiB   
set 1 esp on   
mkpart primary ext4 512MiB 100%; then
ok “Partition table created.”
else
err “Partitioning failed on ${PRIMARY_DEV}.”
fi

if [[ “$PRIMARY_DEV” == *nvme* ]]; then
BOOT_PART=”${PRIMARY_DEV}p1”
ROOT_PART=”${PRIMARY_DEV}p2”
else
BOOT_PART=”${PRIMARY_DEV}1”
ROOT_PART=”${PRIMARY_DEV}2”
fi

log “Formatting boot partition (FAT32)…”
sudo mkfs.fat -F 32 -n BOOT “$BOOT_PART” && ok “Boot: ${BOOT_PART}”   
|| warn “mkfs.fat failed on ${BOOT_PART}”

log “Formatting root partition (ext4)…”
sudo mkfs.ext4 -L nixos “$ROOT_PART” && ok “Root: ${ROOT_PART}”   
|| warn “mkfs.ext4 failed on ${ROOT_PART}”

log “Mounting root…”
sudo mount “$ROOT_PART” /mnt && ok “Mounted ${ROOT_PART} → /mnt”   
|| err “Mount failed for ${ROOT_PART}”

sudo mkdir -p /mnt/boot
sudo mount “$BOOT_PART” /mnt/boot && ok “Mounted ${BOOT_PART} → /mnt/boot”   
|| warn “Boot mount failed for ${BOOT_PART}”

for dev in “${!MOUNT_PATHS[@]}”; do
mpath=”${MOUNT_PATHS[$dev]}”
log “Formatting extra disk ${dev} (ext4)…”
sudo mkfs.ext4 -L “$(basename “$mpath”)” “$dev” && ok “Formatted: ${dev}”   
|| warn “mkfs.ext4 failed on ${dev}”
sudo mkdir -p “/mnt${mpath}”
sudo mount “$dev” “/mnt${mpath}” && ok “Mounted ${dev} → /mnt${mpath}”   
|| warn “Could not mount ${dev} → /mnt${mpath}”
done

log “Generating hardware config…”
sudo nixos-generate-config –root /mnt && ok “hardware-configuration.nix generated.”   
|| warn “nixos-generate-config failed — hardware config may be incomplete”

GENERATED_HW=”/mnt/etc/nixos/hardware-configuration.nix”
if [ -f “$GENERATED_HW” ]; then
cp “$GENERATED_HW” “$DEST/hosts/hardware-configuration.nix”
ok “Copied hardware config to repo.”
else
warn “Could not find generated hardware-configuration.nix at ${GENERATED_HW}”
fi
fi

# ═════════════════════════════════════════════════════════════════════════════

# Phase 9: NixOS Installation

# ═════════════════════════════════════════════════════════════════════════════

phase_header “9” “NixOS Installation”

if [ “$AUTO_INSTALL” -eq 0 ]; then
echo -e “  ${DIM}Manual mode — skipping nixos-install.${R}”
echo “”
echo -e “  Run when ready:”
echo -e “    ${CY}${BOLD}sudo nixos-install –flake /etc/nixos#nixos${R}”
read -r -s -p “  Press Enter to continue…” _
echo “”
else
log “Running nixos-install…”
echo “”
if sudo nixos-install –no-root-passwd –flake /etc/nixos#nixos; then
ok “NixOS installed successfully.”
else
err “nixos-install failed — check logs above. You may retry manually.”
fi
fi

phase_header “10” “Dotfiles & Assets”
log “Linking asset files…”
mkdir -p “$DEST/assets”
cat > “$DEST/assets/fastfetch.json” << ‘ASSET_EOF_fastfetch_json_’
{
“$schema”: “https://github.com/fastfetch-cli/fastfetch/raw/dev/doc/json_schema.json”,
“logo”: {
“type”: “builtin”,
“source”: “nixos_small”,
“color”: {
“1”: “blue”,
“2”: “cyan”
}
},
“display”: {
“separator”: “  “,
“color”: {
“keys”: “blue”,
“title”: “blue”,
“separator”: “cyan”
}
},
“modules”: [
“title”,
“separator”,
“os”,
“kernel”,
“uptime”,
“packages”,
“shell”,
“display”,
“de”,
“wm”,
“terminal”,
“cpu”,
“gpu”,
“memory”,
“disk”,
“separator”,
“colors”
]
}
ASSET_EOF_fastfetch_json_
_apath=”/home/hogoshi/.config/fastfetch/config.json”
_apath=”${_apath//hogoshi/$USERNAME}”
mkdir -p “$(dirname “$_apath”)”
ln -sf “$DEST/assets/fastfetch.json” “$_apath”
log “  linked: assets/fastfetch.json”

cat > “$DEST/assets/hyprland.conf” << ‘ASSET_EOF_hyprland_conf_’
source = ~/.local/share/ambxst/hyprland.conf

monitor = ,3440x1440@180,0x0,1

input {
kb_layout = us
kb_options = grp:alt_shift_toggle
}

misc {
disable_autoreload = false
}
ASSET_EOF_hyprland_conf_
sed -i “s|kb_layout = .*|kb_layout = ${KB_LAYOUT}|” “$DEST/assets/hyprland.conf”
log “  kb_layout → ${KB_LAYOUT}”
_apath=”/home/hogoshi/.config/hypr/hyprland.conf”
_apath=”${_apath//hogoshi/$USERNAME}”
mkdir -p “$(dirname “$_apath”)”
ln -sf “$DEST/assets/hyprland.conf” “$_apath”
log “  linked: assets/hyprland.conf”

log “Installing ambxst…”
if curl -fsSL get.axeni.de/ambxst | sh; then
ok “ambxst installed.”
else
warn “ambxst install failed — run manually: curl -fsSL get.axeni.de/ambxst | sh”
fi

log “Running ambxst install hyprland…”
if ambxst install hyprland; then
ok “ambxst hyprland setup complete.”
else
warn “ambxst install hyprland failed — run manually after reboot.”
fi

log “Setting up ~/.config/ambxst…”
mkdir -p “/home/$USERNAME/.config/ambxst”
chown “$USERNAME:users” “/home/$USERNAME/.config/ambxst” 2>/dev/null || true
chmod a+rwx “/home/$USERNAME/.config/ambxst”
ok “~/.config/ambxst ready.”

# ═════════════════════════════════════════════════════════════════════════════

# Phase 11: Done

# ═════════════════════════════════════════════════════════════════════════════

phase_header “11” “Complete”

if [ ${#ERRORS[@]} -eq 0 ]; then
echo -e “  ${GR}${BOLD}All phases completed without errors.${R}”
else
echo -e “  ${YE}${BOLD}Completed with ${#ERRORS[@]} warning(s):${R}”
echo “”
for e in “${ERRORS[@]}”; do
echo -e “    ${YE}▸${R} ${e}”
done
fi

echo “”
echo -e “  ${BOLD}Summary:${R}”
echo -e “    ${DIM}▸${R} User:     ${CY}${USERNAME}${R}”
echo -e “    ${DIM}▸${R} Config:   ${CY}${DEST}${R}”
echo -e “    ${DIM}▸${R} Keyboard: ${CY}${KB_LAYOUT}${R}”
echo -e “    ${DIM}▸${R} Browser:  ${CY}${BROWSER_CHOICE}${R}”
echo “”
echo -e “  ${BOLD}Next steps:${R}”
if [ “$AUTO_INSTALL” -eq 1 ]; then
echo -e “    ${DIM}1.${R} Reboot:                   ${CY}reboot${R}”
echo -e “    ${DIM}2.${R} Login as:                  ${CY}${USERNAME}${R}  (password: ${CY}${INIT_PASS}${R})”
echo -e “    ${DIM}3.${R} Open Throne (${CY}Super+K${R}), set up VLESS VPN”
echo -e “    ${DIM}4.${R} Edit ${CY}${DEST}/flake.nix${R} → set ${CY}setupMode = false${R}”
echo -e “    ${DIM}5.${R} In kitty (${CY}Super+Enter${R}):   ${CY}rr${R}”
else
echo -e “    ${DIM}1.${R} Install:  ${CY}sudo nixos-install –flake /etc/nixos#nixos${R}”
echo -e “    ${DIM}2.${R} Reboot:   ${CY}reboot${R}”
echo -e “    ${DIM}3.${R} Login as: ${CY}${USERNAME}${R}  (password: ${CY}${INIT_PASS}${R})”
echo -e “    ${DIM}4.${R} Set up VPN, edit flake → ${CY}setupMode = false${R}, run ${CY}rr${R}”
fi
echo “”